:root {
  --bg-card: #1e3a5f;
  --bg-header: #16305a;
  --bg-stats: #16305a;
  --bg-forecast: #243f6a;
  --bg-forecast-active: #3b6faa;
  --color-city: #ffffff;
  --color-country: #7eb8f7;
  --color-date: #7eb8f7;
  --color-temp: #ffffff;
  --color-unit: #7eb8f7;
  --color-condition: #c5deff;
  --color-stat-label: #7eb8f7;
  --color-stat-value: #ffffff;
  --color-day-name: #7eb8f7;
  --color-day-temp: #ffffff;
  --border-radius-card: 20px;
  --border-radius-stat: 10px;
  --border-radius-forecast: 12px;
}

body {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
  margin: 0;
}

.weather-widget {
  background: var(--bg-card);
  border-radius: var(--border-radius-card);
  width: 300px;
  overflow: hidden;
}

.weather-header {
  background: var(--bg-header);
  padding: 20px 24px 16px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.location {
  display: flex;
  align-items: baseline;
  gap: 8px;
}

.city {
  font-size: 18px;
  font-weight: 700;
  color: var(--color-city);
}

.country {
  font-size: 13px;
  font-weight: 600;
  color: var(--color-country);
}

.date-label {
  font-size: 12px;
  font-weight: 500;
  color: var(--color-date);
}

.weather-main {
  padding: 20px 24px 16px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.temp-block {
  display: flex;
  align-items: flex-start;
  line-height: 1;
}

.temp-value {
  font-size: 64px;
  font-weight: 800;
  color: var(--color-temp);
  line-height: 1;
}

.temp-unit {
  font-size: 24px;
  font-weight: 600;
  color: var(--color-unit);
  margin-top: 8px;
}

.condition-block {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
}

.condition-icon {
  font-size: 40px;
  line-height: 1;
}

.condition-text {
  font-size: 12px;
  font-weight: 500;
  color: var(--color-condition);
  text-align: center;
}

.weather-stats {
  background: var(--bg-stats);
  margin: 0 16px 16px;
  border-radius: var(--border-radius-stat);
  display: flex;
  justify-content: space-around;
  padding: 12px 8px;
}

.stat {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 4px;
}

.stat-label {
  font-size: 11px;
  font-weight: 500;
  color: var(--color-stat-label);
}

.stat-value {
  font-size: 15px;
  font-weight: 700;
  color: var(--color-stat-value);
}

.forecast-row {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 8px;
  padding: 0 16px 20px;
}

.forecast-day {
  background: var(--bg-forecast);
  border-radius: var(--border-radius-forecast);
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 10px 4px;
  gap: 6px;
}

.forecast-day.active {
  background: var(--bg-forecast-active);
}

.day-name {
  font-size: 10px;
  font-weight: 700;
  color: var(--color-day-name);
  letter-spacing: 0.05em;
}

.day-icon {
  font-size: 20px;
  line-height: 1;
}

.day-temp {
  font-size: 13px;
  font-weight: 700;
  color: var(--color-day-temp);
}
